#!/usr/bin/env python3
"""Real-time ad-creative tracker. Reads ClickUp on each request and renders the dashboard.
Env: CLICKUP_TOKEN. Run: gunicorn app:app"""
import os, json, base64, time, urllib.request, urllib.error
from datetime import datetime, timezone
try:
    from zoneinfo import ZoneInfo
    LONDON = ZoneInfo("Europe/London")
except Exception:
    LONDON = timezone.utc
from flask import Flask, Response

TEMPLATE = base64.b64decode("").decode()

LIST_TO_CLIENT = {
    "901213433755": "Mission Beard", "901212351334": "Brylamar",
    "901216572550": "Squeak n Snap", "901216938255": "Peela Nails",
    "901217825368": "Vita Sciences", "901219086285": "Boy Box",
    "901219393993": "Mowe Beauty",
}
CLIENT_ORDER = ["Vita Sciences", "Peela Nails", "Squeak n Snap", "Boy Box",
                "Brylamar", "Mission Beard", "Mowe Beauty"]
STAGE = {
    "idea stage": ("idea", "production"), "approved": ("approved", "production"),
    "sent to graphic designer": ("design", "production"),
    "sent to video editor": ("edit", "production"),
    "testing stage": ("testing", "live"), "testing": ("testing", "live"),
    "top performing": ("top", "live"),
    "complete": ("complete", "done"), "rejected": ("rejected", "killed"),
}
BOARD_STAGES = {"approved", "design", "edit"}

_CACHE = {"html": None, "ts": 0}
CACHE_TTL = 30  # seconds; keeps it real-time while respecting ClickUp rate limits


def api_get(url, token):
    req = urllib.request.Request(url, headers={"Authorization": token})
    with urllib.request.urlopen(req, timeout=30) as r:
        return json.loads(r.read().decode())


def fetch_list(list_id, token):
    out, page = [], 0
    while True:
        url = ("https://api.clickup.com/api/v2/list/%s/task"
               "?include_closed=true&subtasks=false&page=%d" % (list_id, page))
        data = api_get(url, token)
        tasks = data.get("tasks", [])
        out.extend(tasks)
        if data.get("last_page") is True or not tasks:
            break
        page += 1
        if page > 50:
            break
    return out


def build_html():
    token = os.environ.get("CLICKUP_TOKEN", "").strip()
    if not token:
        return "<h1>CLICKUP_TOKEN not configured</h1>"
    raw = []
    for lid in LIST_TO_CLIENT:
        raw.extend(fetch_list(lid, token))
    rows = []
    last_by_client = {c: None for c in CLIENT_ORDER}
    global_last = 0
    for t in raw:
        lid = str(t.get("list", {}).get("id", ""))
        client = LIST_TO_CLIENT.get(lid)
        if not client:
            continue
        status = (t.get("status") or {}).get("status", "")
        stage, cat = STAGE.get(status, ("other", "production"))
        closed = t.get("date_closed") is not None
        created = int(t["date_created"]) if t.get("date_created") else None
        assignees = [a.get("username") for a in t.get("assignees", []) if a.get("username")]
        rows.append({
            "id": t.get("id"), "name": t.get("name", ""), "url": t.get("url", ""),
            "client": client, "stage": stage, "cat": cat, "assignees": assignees,
            "closed": closed,
            "board": (stage in BOARD_STAGES) and (not closed),
            "extra": (stage in ("idea", "testing")) and (not closed),
        })
        if cat == "live" and created:
            if last_by_client[client] is None or created > last_by_client[client]:
                last_by_client[client] = created
            if created > global_last:
                global_last = created
    gen_label = datetime.now(LONDON).strftime("%-d %b %Y, %H:%M:%S %Z")
    html = (TEMPLATE
            .replace("__DATA__", json.dumps(rows, ensure_ascii=False))
            .replace("__CLIENTS__", json.dumps(CLIENT_ORDER, ensure_ascii=False))
            .replace("__LASTTESTCLIENT__", json.dumps(last_by_client))
            .replace("__LASTTEST__", str(global_last))
            .replace("__GEN__", gen_label)
            .replace("Auto-updates every 15 min", "Live \u2014 updates on every load"))
    return html


app = Flask(__name__)


@app.route("/")
def index():
    now = time.time()
    if _CACHE["html"] and (now - _CACHE["ts"] < CACHE_TTL):
        html = _CACHE["html"]
    else:
        try:
            html = build_html()
            _CACHE["html"] = html
            _CACHE["ts"] = now
        except Exception as e:
            if _CACHE["html"]:
                html = _CACHE["html"]  # serve last good copy on transient error
            else:
                return Response("<h1>Temporary error reading ClickUp</h1><pre>%s</pre>" % str(e)[:300],
                                status=503, mimetype="text/html")
    return Response(html, mimetype="text/html",
                    headers={"Cache-Control": "no-store, max-age=0"})


@app.route("/healthz")
def healthz():
    return "ok"


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "10000")))
